<template><view class="page"><view class="hero"><view class="avatar">{{initial}}</view><view><text class="name">{{store.isLoggedIn?(store.userInfo?.nickname||'用户'):'未登录'}}</text><text class="muted light">ID：{{store.userInfo?.userId||'--'}} · {{realNameLabel(store.userInfo?.realNameStatus)}} · {{store.userInfo?.levelName||'普通会员'}}</text></view></view><view v-if="!store.isLoggedIn" class="card"><button class="primary" @click="go('/pages/login/index')">登录 / 注册</button></view><view class="grid card"><view @click="go('/pages/wallet/index')">资产</view><view @click="go('/pages/team/index')">团队</view><view @click="go('/pages/order/list/index')">订单</view><view @click="go('/pages/aftersale/index')">售后</view><view @click="go('/pages/address/list/index')">地址</view><view @click="go('/pages/settings/index')">设置</view><view @click="go('/pages/auth/realname/index')">实名认证</view><view @click="go('/pages/content/list/index')">内容中心</view></view></view></template><script setup lang="ts">import { computed } from 'vue';import { onShow } from '@dcloudio/uni-app';import { useUserStore } from '@/store/user';import { refreshUserInfo } from '@/services/user';import { realNameLabel } from '@/utils/auth';const store=useUserStore();const initial=computed(()=>store.isLoggedIn?(store.userInfo?.nickname||'用').slice(0,1):'未');function go(url:string){uni.navigateTo({url})}onShow(()=>{if(store.isLoggedIn)refreshUserInfo().catch(()=>{})})</script><style scoped lang="scss">.page{min-height:100vh;background:#f6f1e8;color:#24170c}.hero{background:#2b1207;color:#fff;padding:110rpx 30rpx 38rpx;display:flex;gap:24rpx;align-items:center}.avatar{width:116rpx;height:116rpx;border-radius:50%;background:#f0bf55;color:#2b1207;display:flex;align-items:center;justify-content:center;font-size:38rpx;font-weight:900}.name{display:block;font-size:36rpx;font-weight:900}.muted{color:#8d8175;font-size:24rpx}.light{color:#e8d6b8}.card{background:#fff;margin:20rpx;padding:28rpx;border-radius:16rpx}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:18rpx}.grid view{height:110rpx;background:#fff8e8;border-radius:12rpx;display:flex;align-items:center;justify-content:center;font-weight:800}button{height:84rpx;line-height:84rpx;width:100%;border:0;border-radius:999rpx}.primary{background:#b97700;color:#fff}button:after{border:0}</style>
